   import { getDestination, Destination } from '@sap-cloud-sdk/connectivity';
   import { config } from '../config/index.js';
   import { logger } from '../config/logger.js';

   let cachedDestination: Destination | null = null;
   let cacheExpiry: number = 0;
   const CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes

   export async function getCloudIntegrationDestination(): Promise<Destination> {
     const now = Date.now();
     if (cachedDestination && now < cacheExpiry) {
       return cachedDestination;
     }

     logger.debug(`Resolving destination: ${config.sapDestinationName}`);

     try {
       const destination = await getDestination({
         destinationName: config.sapDestinationName,
         useCache: true
       });

       if (!destination) {
         throw new Error(`Destination '${config.sapDestinationName}' not found`);
       }

       cachedDestination = destination;
       cacheExpiry = now + CACHE_TTL_MS;

       logger.info(`Destination resolved: ${destination.url}`);
       return destination;
     } catch (error) {
       logger.error('Failed to resolve destination', { error });
       throw error;
     }
   }

   export function getBaseUrl(destination: Destination): string {
     return `${destination.url}/api/v1`;
   }

   export function clearDestinationCache(): void {
     cachedDestination = null;
     cacheExpiry = 0;
   }
   ```

