   ```typescript
   import { executeHttpRequest } from '@sap-cloud-sdk/http-client';
   import { Destination } from '@sap-cloud-sdk/connectivity';
   import { logger } from '../config/logger.js';

   interface CsrfToken {
     token: string;
     cookies: string[];
     fetchedAt: number;
   }

   const TOKEN_TTL_MS = 10 * 60 * 1000; // 10 minutes
   let cachedToken: CsrfToken | null = null;

   export async function fetchCsrfToken(
     destination: Destination,
     baseUrl: string
   ): Promise<CsrfToken> {
     const now = Date.now();
     if (cachedToken && now - cachedToken.fetchedAt < TOKEN_TTL_MS) {
       return cachedToken;
     }

     logger.debug('Fetching CSRF token');

     const response = await executeHttpRequest(destination, {
       method: 'get',
       url: baseUrl,
       headers: { 'X-CSRF-Token': 'Fetch' }
     });

     const token = response.headers['x-csrf-token'];
     const setCookies = response.headers['set-cookie'] || [];
     const cookies = Array.isArray(setCookies) ? setCookies : [setCookies];

     if (!token) {
       throw new Error('No CSRF token in response');
     }

     cachedToken = { token, cookies, fetchedAt: now };
     logger.debug('CSRF token fetched successfully');
     return cachedToken;
   }

   export function clearCsrfCache(): void {
     cachedToken = null;
   }
   ```

