   import { executeHttpRequest, HttpResponse } from '@sap-cloud-sdk/http-client';
   import { getCloudIntegrationDestination, getBaseUrl } from './destination.js';
   import { fetchCsrfToken, clearCsrfCache } from './csrf-manager.js';
   import { config } from '../config/index.js';
   import { logger } from '../config/logger.js';

   export interface ODataQueryOptions {
     $filter?: string;
     $select?: string;
     $expand?: string;
     $top?: number;
     $skip?: number;
     $orderby?: string;
     $inlinecount?: 'allpages' | 'none';
   }

   function buildQueryString(options?: ODataQueryOptions): string {
     if (!options) return '';
     const params = new URLSearchParams();
     for (const [key, value] of Object.entries(options)) {
       if (value !== undefined) params.append(key, String(value));
     }
     const qs = params.toString();
     return qs ? `?${qs}` : '';
   }

   export async function odataGet<T>(
     entitySet: string,
     key?: string,
     options?: ODataQueryOptions
   ): Promise<T> {
     const destination = await getCloudIntegrationDestination();
     const baseUrl = getBaseUrl(destination);
     const keyPart = key ? `(${key})` : '';
     const url = `${baseUrl}/${entitySet}${keyPart}${buildQueryString(options)}`;

     logger.debug(`OData GET: ${url}`);

     const response = await executeHttpRequest(destination, {
       method: 'get',
       url,
       headers: { Accept: 'application/json' },
       timeout: config.requestTimeout
     });

     return response.data as T;
   }

   export async function odataPost<T>(
     entitySet: string,
     data: Record<string, unknown>
   ): Promise<T> {
     const destination = await getCloudIntegrationDestination();
     const baseUrl = getBaseUrl(destination);
     const csrf = await fetchCsrfToken(destination, baseUrl);

     const response = await executeHttpRequest(destination, {
       method: 'post',
       url: `${baseUrl}/${entitySet}`,
       data,
       headers: {
         'Content-Type': 'application/json',
         Accept: 'application/json',
         'X-CSRF-Token': csrf.token,
         Cookie: csrf.cookies.join('; ')
       }
     });

     return response.data as T;
   }

   // Similar implementations for odataPatch, odataDelete
   ```

