   ```typescript
   export interface ODataError {
     code: string;
     message: string;
     details?: string;
     httpStatus?: number;
   }

   export function parseODataError(error: unknown): ODataError {
     if (error instanceof Error && 'response' in error) {
       const response = (error as any).response;
       const data = response?.data;

       // OData V2 error format
       if (data?.error) {
         return {
           code: data.error.code || 'UNKNOWN',
           message: data.error.message?.value || data.error.message || 'Unknown error',
           details: data.error.innererror?.errordetails?.[0]?.message,
           httpStatus: response.status
         };
       }

       return {
         code: `HTTP_${response.status}`,
         message: response.statusText || 'HTTP Error',
         httpStatus: response.status
       };
     }

     return {
       code: 'UNKNOWN',
       message: error instanceof Error ? error.message : String(error)
     };
   }

   export function formatErrorForUser(error: ODataError): string {
     let msg = error.message;
     if (error.details) msg += ` - ${error.details}`;
     if (error.httpStatus === 403) {
       msg += ' (Check authorization roles on Process Integration Runtime service instance)';
     }
     return msg;
   }
